3	const PROCESSING_FEE = 5;
4	const FIRST_INSURANCE_RATE = 0.1;
5	
6	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	  rune: 25,
12	  moonstone: 25,
13	};
14	
15	const COMPONENT_TYPES = new Set<string>(["rune", "moonstone"]);
16	const COMPONENT_BLOCK_SIZE = 3;
17	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
18	const CURSED_SURCHARGE_RATE = 0.5;
19	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
20	const HIGH_ENCHANTMENT_THRESHOLD = 5;
21	const LOYALTY_DISCOUNT_RATE = 0.2;
22	const LOYALTY_YEARS_THRESHOLD = 2;
23	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
24	
25	function loyaltyDiscountFor(yearsInsured: number, baseTotal: number): number {
26	  return yearsInsured >= LOYALTY_YEARS_THRESHOLD ? baseTotal * LOYALTY_DISCOUNT_RATE : 0;
27	}
28	
29	function followUpDiscountFor(contractNumber: number, baseTotal: number): number {
30	  return contractNumber > 1 ? baseTotal * FOLLOW_UP_DISCOUNT_RATE : 0;
31	}
32	
33	function withFirstInsurance(basePremium: number): number {
34	  return basePremium + basePremium * FIRST_INSURANCE_RATE;
35	}
36	
37	function premiumForTypeGroup(type: string, count: number): number {
38	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
39	    return withFirstInsurance(COMPONENT_BLOCK_BASE_PREMIUM);
40	  }
41	  return count * withFirstInsurance(BASE_PREMIUM_BY_ITEM_TYPE[type]);
42	}
43	
44	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
45	
46	function surchargeRateForItem(item: Item): number {
47	  const cursedRate = item.cursed ? CURSED_SURCHARGE_RATE : 0;
48	  const enchantmentRate =
49	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
50	      ? HIGH_ENCHANTMENT_SURCHARGE_RATE
51	      : 0;
52	  return cursedRate + enchantmentRate;
53	}
54	
55	function surchargeForItem(item: Item): number {
56	  return BASE_PREMIUM_BY_ITEM_TYPE[item.type] * surchargeRateForItem(item);
57	}
58	
59	const CLAIM_DEDUCTIBLE = 100;
60	const CAP_MULTIPLIER = 2;
61	const REDUCED_REIMBURSEMENT_RATE = 0.5;
62	const REDUCED_REIMBURSEMENT_ENCHANTMENT_THRESHOLD = 8;
63	const MATERIALS_EXEMPT_FROM_REDUCED_REIMBURSEMENT = new Set<string>(["dragon"]);
64	
65	const INSURANCE_VALUE_BY_ITEM_TYPE: Record<string, number> = {
66	  sword: 1000,
67	  amulet: 600,
68	  staff: 800,
69	  potion: 400,
70	  rune: 250,
71	  moonstone: 250,
72	};
73	
74	type Damage = { type: string; amount: number };
75	
76	function insuranceCapFor(items: Item[]): number {
77	  const insuranceSum = items.reduce(
78	    (sum, item) => sum + INSURANCE_VALUE_BY_ITEM_TYPE[item.type],
79	    0,
80	  );
81	  return insuranceSum * CAP_MULTIPLIER;
82	}
83	
84	function isExemptFromReducedReimbursement(item: Item): boolean {
85	  return (
86	    COMPONENT_TYPES.has(item.type) ||
87	    MATERIALS_EXEMPT_FROM_REDUCED_REIMBURSEMENT.has(item.material ?? "")
88	  );
89	}
90	
91	function hasReducedReimbursement(item: Item): boolean {
92	  if (isExemptFromReducedReimbursement(item)) return false;
93	  return (item.enchantment ?? 0) >= REDUCED_REIMBURSEMENT_ENCHANTMENT_THRESHOLD;
94	}
95	
96	function reimbursementFor(damage: Damage, items: Item[]): number {
97	  const matchingItem = items.find((item) => item.type === damage.type);
98	  if (matchingItem && hasReducedReimbursement(matchingItem)) {
99	    return damage.amount * REDUCED_REIMBURSEMENT_RATE;
100	  }
101	  return damage.amount;
102	}
103	
104	function rawPayoutFor(damages: Damage[], items: Item[]): number {
105	  const reimbursementTotal = damages.reduce(
106	    (sum, d) => sum + reimbursementFor(d, items),
107	    0,
108	  );
109	  return reimbursementTotal - CLAIM_DEDUCTIBLE;
110	}
111	
112	function handleClaim(scenario: any): { payout: number; remainingCap: number } {
113	  const damages: Damage[] = scenario.damages ?? [];
114	  const items: Item[] = scenario.items ?? [];
115	  const payout = Math.floor(rawPayoutFor(damages, items));
116	  return { payout, remainingCap: insuranceCapFor(items) - payout };
117	}
118	
119	function handleQuote(scenario: any): { premium: number } {
120	  const items: Item[] = scenario.items ?? [];
121	  const countsByType: Record<string, number> = {};
122	  let surchargesTotal = 0;
123	  let baseTotal = 0;
124	  for (const item of items) {
125	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
126	    surchargesTotal += surchargeForItem(item);
127	    baseTotal += BASE_PREMIUM_BY_ITEM_TYPE[item.type];
128	  }
129	  let itemsTotal = 0;
130	  for (const type of Object.keys(countsByType)) {
131	    itemsTotal += premiumForTypeGroup(type, countsByType[type]);
132	  }
133	  const yearsInsured = scenario.customer?.yearsInsured ?? 0;
134	  const contractNumber = scenario.customer?.contractNumber ?? 1;
135	  const loyaltyDiscount = loyaltyDiscountFor(yearsInsured, baseTotal);
136	  const followUpDiscount = followUpDiscountFor(contractNumber, baseTotal);
137	  return {
138	    premium: Math.ceil(itemsTotal + surchargesTotal - loyaltyDiscount - followUpDiscount + PROCESSING_FEE),
139	  };
140	}
141	
142	function runSteps(scenario: any): unknown {
143	  const customer = scenario.customer;
144	  const policies: { items: Item[]; remainingCap: number }[] = [];
145	  const results: unknown[] = [];
146	  for (const step of scenario.steps) {
147	    if (step.op === "quote") {
148	      const items: Item[] = step.items ?? [];
149	      results.push(handleQuote({ customer, items }));
150	      policies.push({ items, remainingCap: insuranceCapFor(items) });
151	    } else if (step.op === "claim") {
152	      const policy = policies[step.policy];
153	      const damages: Damage[] = step.damages ?? [];
154	      const payout = Math.floor(Math.min(rawPayoutFor(damages, policy.items), policy.remainingCap));
155	      policy.remainingCap -= payout;
156	      results.push({ payout, remainingCap: policy.remainingCap });
157	    }
158	  }
159	  return { results };
160	}
161	
162	export function runScenario(scenario: any): unknown {
163	  if (scenario.steps) {
164	    return runSteps(scenario);
165	  }
166	  if (scenario.command === "claim") {
167	    return handleClaim(scenario);
168	  }
169	  return handleQuote(scenario);
170	}
